mapper.update:
/* 에이전트 활성/비활성 agent.updateAgentUseYn */
UPDATE TB_AGT
SET USE_YN = #{useYn}
WHERE AGENT_ID = #{agentId}

mapper.select:
/* 에이전트 상세 조회 agent.selectAgent */ SELECT A.AGENT_ID , A.AGENT_NM , A.AGENT_TYPE_CD , A.DESCRIPTION , A.SORT_ORD , A.USE_YN , A.LAST_MDF_DT , A.CREATE_DT , A.MODIFY_DT ${dynamicQuery} FROM TB_AGT A
LEFT JOIN TB_AGT_RAG_CFG B ON A.AGENT_ID = B.AGENT_ID
LEFT JOIN TB_AGT_SQL_CFG B ON A.AGENT_ID = B.AGENT_ID
WHERE 1=1 AND A.AGENT_ID = #{agentId}
